mapper.select:
SELECT id, -- 계약 고유번호 contract_date AS contractDate, -- 계약일 sgg_cd AS sggCd, -- 시군구 코드 sgg_nm AS sggNm, -- 시군구 이름 umd_nm AS umdNm, -- 법정동 이름 jibun, -- 지번 주소 name, -- 오피스텔 단지명 deposit, -- 보증금 monthly_rent AS monthlyRent, -- 월세 area, -- 전용 면적 build_year AS buildYear, -- 건축 년도 floor, -- 층수 contract_term AS contractTerm, -- 계약 기간 contract_type AS contractType -- 계약 종류 (신규/갱신) FROM rent_complete
AND sgg_cd = SUBSTRING(#{sggCd}, 1, 5)
AND umd_nm = #{umdNm}
AND name LIKE CONCAT('%', #{name}, '%')
AND deposit BETWEEN #{minDeposit} AND #{maxDeposit}
AND monthly_rent BETWEEN #{minRent} AND #{maxRent}
ORDER BY contract_date DESC
